parameters.query:
SELECT channel_type, day_of_week, hour_of_day, is_holiday_us, is_holiday_de, recommendation_rank
FROM s_motherduck.timeslot_recommendations
ORDER BY channel_type, recommendation_rank ASC;

SELECT holiday_date, country_code
FROM s_motherduck.public_holidays
WHERE holiday_date::date >= CURRENT_DATE AND holiday_date::date <= CURRENT_DATE + INTERVAL '3 months';

parameters.jsCode:
const approvedPosts = $('Fetch Approved Unscheduled').all().filter(p => p.json && p.json.id);
const futureScheduled = $('Fetch Future Scheduled').all().filter(p => p.json && p.json.scheduled_at);
const rawRecs = $('Fetch Timeslot Recommendations').all().map(r => r.json);
const holidaysList = $('Fetch Public Holidays').all().map(h => h.json);

if (approvedPosts.length === 0) {
  return [];
}

const updates = [];
const channels = ['individual', 'databiz'];
const channelMap = {
  'individual': 'personal',
  'databiz': 'company'
};

const holidays = new Set(holidaysList.map(h => {
  if (!h.holiday_date || !h.country_code) return '';
  const dateStr = h.holiday_date.split('T')[0];
  return `${dateStr}:${h.country_code.toUpperCase()}`;
}).filter(Boolean));

function isHoliday(date, countryCode) {
  const dateStr = date.toFormat('yyyy-MM-dd');
  return holidays.has(`${dateStr}:${countryCode.toUpperCase()}`);
}

for (const chan of channels) {
  const chanApproved = approvedPosts.filter(p => p.json.channel === chan);
  if (chanApproved.length === 0) continue;

  const predChan = channelMap[chan];
  const chanRecs = rawRecs.filter(r => r.channel_type === predChan);
  const chanFuture = futureScheduled.filter(p => p.json.channel === chan);

  let start = DateTime.now().setZone('Europe/Berlin');
  const scheduledSlots = new Set(chanFuture.map(p => {
    if (!p.json.scheduled_at) return '';
    return DateTime.fromISO(p.json.scheduled_at).setZone('Europe/Berlin').toFormat('yyyy-MM-dd HH:mm');
  }).filter(Boolean));

  function getNextSlot(dt) {
    let candidate = dt.plus({ hours: 1 }).set({ minute: 0, second: 0, millisecond: 0 });
    const limit = dt.plus({ days: 30 });
    while (candidate < limit) {
      const isHolUS = isHoliday(candidate, 'US');
      const isHolDE = isHoliday(candidate, 'DE');
      const dbDayOfWeek = candidate.weekday - 1;
      const hour = candidate.hour;

      const matchingRec = chanRecs.find(r => 
        r.day_of_week === dbDayOfWeek &&
        r.hour_of_day === hour &&
        r.is_holiday_us === isHolUS &&
        r.is_holiday_de === isHolDE
      );

      if (matchingRec && matchingRec.recommendation_rank <= 10) {
        return candidate;
      }
      candidate = candidate.plus({ hours: 1 });
    }
    return dt.plus({ days: 1 }).set({ hour: 15, minute: 0, second: 0, millisecond: 0 });
  }

  let currentPointer = start;
  for (const post of chanApproved) {
    let slot = getNextSlot(currentPointer);
    while (scheduledSlots.has(slot.toFormat('yyyy-MM-dd HH:mm'))) {
      slot = getNextSlot(slot);
    }

    updates.push({
      json: {
        id: post.json.id,
        scheduled_at: slot.toUTC().toISO(),
        timezone: 'Europe/Berlin'
      }
    });

    scheduledSlots.add(slot.toFormat('yyyy-MM-dd HH:mm'));
    currentPointer = slot;
  }
}

return updates;
